using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var notepad = new Notepad();

// --- Define tools via AIFunctionFactory ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        WebSearchTool.SearchAsync,
        nameof(WebSearchTool.SearchAsync),
        "Search the web for information on a given query. Returns relevant text snippets."),
    AIFunctionFactory.Create(
        notepad.AddNote,
        nameof(notepad.AddNote),
        "Save a research note with a title and body for later summarization."),
    AIFunctionFactory.Create(
        notepad.GetNotes,
        nameof(notepad.GetNotes),
        "Retrieve all saved research notes."),
};

// --- Build the ChatClientAgent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches a topic by searching the web and taking notes, then produces a summary.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run the agent ---
var prompt = $"""
    Research the following topic by performing multiple web searches to gather diverse information.
    After each search, save the key findings as a note using the note-taking tool.
    Once you have gathered enough information (at least 3 searches), retrieve all your notes
    and produce a well-structured summary of your findings.

    Topic: {topic}
    """;

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(prompt, session);

// --- Display results ---
Console.WriteLine("═══ Research Summary ═══\n");

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant)
    {
        Console.WriteLine(message.Text);
    }
}

Console.WriteLine("\n═══ Collected Notes ═══\n");
var allNotes = notepad.GetNotes();
Console.WriteLine(allNotes);

return 0;

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>
/// Searches the web using the Bing Search API or falls back to a simulated search.
/// </summary>
static class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        // Use DuckDuckGo Instant Answer API (no key required)
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_httpClient.GetStringAsync(url);

            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}");
            sb.AppendLine();

            // Abstract (main summary)
            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                sb.AppendLine($"[{source}] {abstractText}");
                sb.AppendLine();
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                int count = 0;
                foreach (var item in topics.EnumerateArray())
                {
                    if (count >= 5) break;
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        sb.AppendLine($"- {text}");
                        count++;
                    }
                }
            }

            var result = sb.ToString().Trim();
            return string.IsNullOrWhiteSpace(result) || result.Length < 50
                ? $"Search for '{query}' returned limited results. Try refining the query."
                : result;
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>
/// In-memory notepad for the agent to collect research findings.
/// </summary>
sealed class Notepad
{
    private readonly List<(string Title, string Body)> _notes = [];

    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The content/body of the note")] string body)
    {
        _notes.Add((title, body));
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i].Title}");
            sb.AppendLine(_notes[i].Body);
            sb.AppendLine();
        }

        return sb.ToString().TrimEnd();
    }
}

